qry:select.qry:xquery:
for $r in sql(' select SUM(LIQ20_TOT_LIQ_PER.n_{%=substring(#PARAM:@c_variable,3) %} ) as n_valor
from LIQ19_LIQUIDACION, LIQ19_EJECUCIONES, LIQ99_LIQUIDACION, LIQ99_RECIBOS, LIQ20_TOT_LIQ_PER, ORG03_EMPRESAS, PER02_PERSONAL_EMP, LIQ97_PERSONAL_EMP where LIQ19_LIQUIDACION.c_estado=\'C\' and LIQ99_LIQUIDACION.c_estado=\'F\' and LIQ19_LIQUIDACION.oi_liquidacion=LIQ19_EJECUCIONES.oi_liquidacion and LIQ99_LIQUIDACION.oi_liquidacion_ddo=LIQ19_EJECUCIONES.oi_liquidacion_ddo and LIQ99_LIQUIDACION.oi_liquidacion_ddo=LIQ99_RECIBOS.oi_liquidacion_ddo and LIQ20_TOT_LIQ_PER.oi_tot_liq_per=LIQ99_RECIBOS.oi_tot_liq_per and ORG03_EMPRESAS.oi_empresa = PER02_PERSONAL_EMP.oi_empresa AND ORG03_EMPRESAS.c_empresa = LIQ97_PERSONAL_EMP.c_empresa AND PER02_PERSONAL_EMP.e_numero_legajo = LIQ97_PERSONAL_EMP.e_numero_legajo AND LIQ97_PERSONAL_EMP.oi_per_emp_ddo = LIQ20_TOT_LIQ_PER.oi_per_emp_ddo AND PER02_PERSONAL_EMP.oi_personal_emp = {#PARAMIN:@oi_personal_emp} AND LIQ19_LIQUIDACION.e_periodo = {#PARAMIN:@e_periodo}
')/ROWS/ROW

